class Solution {
public:
    string categorizeBox(int length, int width, int height, int mass) {
        if (length >= 104 || width >= 104 || height >= 104 || length * width * height >= 1e9) {
            if (mass >= 100) return "Both";
            return "Bulky";
        } else if (mass >= 100) return "Heavy";
        return "Neither";
    }
};
